  ('diplomatic-d3cf880d-moex-00570', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-bf235e6a', 'sub-diplomatic-d3cf880d-06', NULL, 'single_choice', '關於「公眾外交」與「傳統外交」，下列敘述何者正確？', '["「公眾外交」的關鍵角色是國家，「傳統外交」的關鍵角色則是人民", "「公眾外交」的目標是塑造喜好，「傳統外交」的目標是灌輸觀念", "「公眾外交」的權力來源是強制力，「傳統外交」的權力來源是吸引力", "「公眾外交」透過宣傳維繫，「傳統外交」透過夥伴關係維繫"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "66532e967a5b", "answer_pdf_sha1": "b80cfb7f05e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00571', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-bf235e6a', 'sub-diplomatic-d3cf880d-06', NULL, 'single_choice', '「在宣傳過程中，消息來源可被清楚辨識，訊息內容也合理地接近事實，然而宣傳的結果往往偏袒 傳送方」。本項敘述指的是何種宣傳方式？', '["無色宣傳", "白色宣傳", "灰色宣傳", "黑色宣傳"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "66532e967a5b", "answer_pdf_sha1": "b80cfb7f05e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00572', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-bf235e6a', 'sub-diplomatic-d3cf880d-06', NULL, 'single_choice', '下列敘述，何者不能算是「公眾外交」（publicdiplomacy）？', '["政府宣傳「東海和平倡議協議」，增進各國了解我國參與國際社會的決心", "臺灣在新冠肺炎疫情期間宣揚TaiwanCanHelp，提供醫療援助給國際社會", "臺北市辦理2017年世界大學運動會，接待各國選手", "臺灣事實查核中心查核疫情期間流傳的假新聞"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "66532e967a5b", "answer_pdf_sha1": "b80cfb7f05e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00573', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-110-bf235e6a', 'sub-diplomatic-d3cf880d-06', NULL, 'single_choice', '國際新聞媒體與知名新聞記者被認為在國際政治及外交領域扮演日益重要之角色，因此衍生出 「媒體仲介外交」之概念。下列何者不屬於此概念之實踐方式？', '["在政府的指引下協助展演一場即時的媒體大秀", "積極並主動地介入與參與協調兩國之間的衝突", "舉辦公開論壇以提供敵對雙方面對面商討爭議問題之機會與管道", "暫不揭露進行中之國際談判之細節，以利危機之解決"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:48+00:00", "source_pdf_sha1": "66532e967a5b", "answer_pdf_sha1": "b80cfb7f05e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際傳播", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL)
